const input = $('Project Input').first().json;
const weather = $('Get Weather').first().json;
let elevation = null;
try { elevation = $('Get Elevation').first().json.results[0].elevation; } catch (e) {}
let nearby = [];
try {
  nearby = ($('Get Nearby Context').first().json.elements || [])
    .map(e => ({ name: (e.tags && e.tags.name) || 'unnamed', place_type: e.tags && e.tags.place }));
} catch (e) {}

const site_data = {
  location: { latitude: input.latitude, longitude: input.longitude, region_name: input.region_name, elevation_m: elevation },
  site: { width_m: input.site_width_m, length_m: input.site_length_m, area_m2: input.site_width_m * input.site_length_m, notes: input.notes },
  weather: { current: weather.current_weather || null, daily: weather.daily || null },
  nearby_settlements_50km: nearby,
  demographics: { population_estimate: input.population_estimate },
  budget_usd: input.budget_usd
};
return [{ json: { site_data } }];

