const validators = [
  $('Parse Fire & Safety Validator').first().json.validator_report,
  $('Parse Traffic & Roads Validator').first().json.validator_report,
  $('Parse Environmental Validator').first().json.validator_report,
  $('Parse Infrastructure Validator').first().json.validator_report,
  $('Parse Accessibility & Social Validator').first().json.validator_report,
];
let totalScore = 0, allCompliant = true;
const issues = [];
for (const v of validators) {
  totalScore += (v.score_pct || 0);
  if (!v.is_compliant) allCompliant = false;
  (v.issues || []).forEach(i => issues.push({ validator: v.validator_name, ...i }));
}
return [{ json: {
  is_compliant: allCompliant,
  overall_score_pct: Math.round((totalScore / validators.length) * 10) / 10,
  issues,
  validator_details: validators
} }];

return [{ json: {
  final_plan: $('Parse Builder Plan V1').first().json.plan,
  validation_summary: $('Master Validator').first().json,
  revision_applied: false
} }];

