const r = $json;
const fin = (r.financial_estimate) || {};
const plan = (r.final_city_plan && r.final_city_plan.final_plan) || {};
const massing = (r.massing_3d && r.massing_3d.massing) || [];
const objects2d = (r.plan_2d && r.plan_2d.objects) || [];
const cb = fin.cost_breakdown || {};

function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function money(n){ return (n==null)?'-':('$' + Number(n).toLocaleString('en-US')); }

// Merge massing with 2D positions by id (fallback to grid layout if no position)
const posById = {};
objects2d.forEach(function(o){ posById[o.id] = o; });
let gi = 0;
const buildings = massing.map(function(m){
  const p = posById[m.id];
  let x, z, w, dep;
  if (p) {
    x = p.x_pct; z = p.y_pct; w = p.width_pct || 5; dep = p.height_pct || 5;
  } else {
    const col = gi % 8, row = Math.floor(gi / 8);
    x = 8 + col * 11; z = 10 + row * 11; w = 6; dep = 6; gi++;
  }
  return { id: m.id, type: m.building_type || 'building', floors: m.floors || 1,
           height_m: m.height_m || 10, x: x, z: z, w: w, dep: dep };
});

const districtsRows = (plan.districts||[]).map(function(x){
  return '<tr><td>'+esc(x.id)+'</td><td>'+esc(x.name)+'</td><td>'+esc(x.purpose)+'</td><td>'+esc(x.area_pct)+'%</td></tr>';
}).join('');
const massingRows = massing.map(function(m){
  return '<tr><td>'+esc(m.id)+'</td><td>'+esc(m.building_type)+'</td><td>'+esc(m.floors)+'</td><td>'+esc(m.height_m)+' m</td></tr>';
}).join('');
const phases = (fin.construction_phases||[]).map(function(p){ return '<li>'+esc(p)+'</li>'; }).join('');
const fullJson = esc(JSON.stringify(r, null, 2));
const buildingsJson = JSON.stringify(buildings);

const html =
'<!DOCTYPE html><html lang="en"><head><meta charset="utf-8">' +
'<meta name="viewport" content="width=device-width, initial-scale=1">' +
'<title>Smart City Plan - ' + esc(r.project) + '</title>' +
'<style>' +
'body{margin:0;font-family:system-ui,Arial,sans-serif;color:#1f2937;background:#f8fafc;}' +
'.wrap{max-width:1000px;margin:0 auto;padding:24px;}' +
'h1{color:#111827;} h2{margin-top:32px;} table{width:100%;border-collapse:collapse;} ' +
'th,td{border:1px solid #d1d5db;padding:6px;text-align:left;font-size:14px;} th{background:#f3f4f6;} ' +
'#city3d{width:100%;height:520px;background:#dbeafe;border-radius:10px;display:block;}' +
'pre{background:#0f172a;color:#e2e8f0;padding:16px;border-radius:8px;overflow:auto;max-height:420px;font-size:12px;}' +
'.legend span{display:inline-block;margin:2px 10px 2px 0;font-size:13px;}' +
'.sw{display:inline-block;width:12px;height:12px;border-radius:2px;margin-right:4px;vertical-align:middle;}' +
'</style></head><body><div class="wrap">' +
'<h1>Smart City Plan &mdash; ' + esc(r.project) + '</h1>' +
'<p style="color:#6b7280;">Generated ' + esc(r.generated_at) + ' &middot; Revision applied: ' + esc((r.final_city_plan&&r.final_city_plan.revision_applied)) + '</p>' +

'<h2>Interactive 3D Model</h2>' +
'<p style="color:#6b7280;font-size:13px;">Drag to rotate, scroll to zoom, right-drag to pan. Building height reflects the number of floors.</p>' +
'<div class="legend" id="legend"></div>' +
'<canvas id="city3d"></canvas>' +

'<h2>Financial Estimate</h2>' +
'<p><strong>Total estimated cost:</strong> ' + money(fin.estimated_total_cost_usd) + ' &mdash; <strong>Within budget:</strong> ' + esc(fin.within_budget) + '</p>' +
'<table><tr><th>Buildings</th><th>Roads</th><th>Utilities</th><th>Green space</th><th>Contingency</th></tr>' +
'<tr><td>'+money(cb.buildings)+'</td><td>'+money(cb.roads)+'</td><td>'+money(cb.utilities)+'</td><td>'+money(cb.green_space)+'</td><td>'+money(cb.contingency)+'</td></tr></table>' +
'<p style="color:#6b7280;font-size:13px;">' + esc(fin.notes) + '</p>' +
'<h3>Construction phases</h3><ol>' + phases + '</ol>' +

'<h2>Districts</h2><table><tr><th>ID</th><th>Name</th><th>Purpose</th><th>Area</th></tr>' + districtsRows + '</table>' +

'<h2>3D Massing (' + massing.length + ' objects)</h2>' +
'<table><tr><th>ID</th><th>Type</th><th>Floors</th><th>Height</th></tr>' + massingRows + '</table>' +

'<h2>Full report (JSON)</h2>' +
'<pre>' + fullJson + '</pre>' +
'</div>' +

'<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>' +
'<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>' +
'<script>' +
'var BUILDINGS=' + buildingsJson + ';' +
'var COLORS={residential_tower:0x60a5fa,residential_block:0x93c5fd,mixed_use:0xa78bfa,commercial:0xf59e0b,commercial_tower:0xf59e0b,commercial_block:0xfbbf24,office_tower:0xef4444,retail:0xfb923c,civic_center:0x34d399,transit_hub:0x2dd4bf,school:0x22c55e,hospital:0xec4899,warehouse:0x9ca3af,light_industry:0x6b7280};' +
'function colorFor(t){return COLORS[t]!==undefined?COLORS[t]:0x94a3b8;}' +
'var canvas=document.getElementById("city3d");' +
'var scene=new THREE.Scene();scene.background=new THREE.Color(0xdbeafe);' +
'var camera=new THREE.PerspectiveCamera(55,canvas.clientWidth/canvas.clientHeight,0.1,2000);' +
'camera.position.set(120,110,140);' +
'var renderer=new THREE.WebGLRenderer({canvas:canvas,antialias:true});' +
'renderer.setSize(canvas.clientWidth,canvas.clientHeight,false);renderer.setPixelRatio(window.devicePixelRatio);' +
'var controls=new THREE.OrbitControls(camera,renderer.domElement);controls.enableDamping=true;controls.target.set(50,0,50);' +
'scene.add(new THREE.AmbientLight(0xffffff,0.75));' +
'var dl=new THREE.DirectionalLight(0xffffff,0.7);dl.position.set(80,160,60);scene.add(dl);' +
'var ground=new THREE.Mesh(new THREE.PlaneGeometry(140,140),new THREE.MeshLambertMaterial({color:0xe5e7eb}));' +
'ground.rotation.x=-Math.PI/2;ground.position.set(50,0,50);scene.add(ground);' +
'var grid=new THREE.GridHelper(140,14,0x9ca3af,0xcbd5e1);grid.position.set(50,0.05,50);scene.add(grid);' +
'var HSCALE=0.9;' +
'BUILDINGS.forEach(function(b){' +
'  var w=Math.max(2,b.w||5), dpt=Math.max(2,b.dep||5), h=Math.max(4,(b.height_m||10)*HSCALE);' +
'  var geo=new THREE.BoxGeometry(w,h,dpt);' +
'  var mat=new THREE.MeshLambertMaterial({color:colorFor(b.type)});' +
'  var mesh=new THREE.Mesh(geo,mat);' +
'  mesh.position.set(b.x, h/2, b.z);' +
'  scene.add(mesh);' +
'  var edges=new THREE.LineSegments(new THREE.EdgesGeometry(geo),new THREE.LineBasicMaterial({color:0x1f2937,opacity:0.25,transparent:true}));' +
'  edges.position.copy(mesh.position);scene.add(edges);' +
'});' +
'var types={};BUILDINGS.forEach(function(b){types[b.type]=colorFor(b.type);});' +
'var lg=document.getElementById("legend");Object.keys(types).forEach(function(t){var c="#"+("000000"+types[t].toString(16)).slice(-6);lg.innerHTML+="<span><span class=\\"sw\\" style=\\"background:"+c+"\\"></span>"+t+"</span>";});' +
'function resize(){var w=canvas.clientWidth,h=canvas.clientHeight;renderer.setSize(w,h,false);camera.aspect=w/h;camera.updateProjectionMatrix();}' +
'window.addEventListener("resize",resize);' +
'function animate(){requestAnimationFrame(animate);controls.update();renderer.render(scene,camera);}animate();' +
'</script></body></html>';

const base64 = Buffer.from(html, 'utf8').toString('base64');
return [{
  json: { generated_at: r.generated_at, project: r.project, building_count: buildings.length },
  binary: { data: { data: base64, mimeType: 'text/html', fileName: 'smart-city-report.html' } }
}];
